import React, { useCallback, useMemo, useState } from 'react';
import {
  Select,
  SearchTextInput,
  detectDateRangePreset,
  dispatchAppToast,
  LIN_ERP_LIST_FILTER_LAYOUT,
  LinErpListFilterBar,
  LinPageLayout,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useInAppNavigate } from '../../../router/useInAppNavigate';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherListFilterState } from '../../../hooks/useVoucherListFilterState';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { useVoucherListSelection } from '../../../hooks/useVoucherListSelection';
import { useVoucherListActions } from '../../../hooks/useVoucherListActions';
import { ktService } from '../../../services/kt/ktService';
import type { BankInternalTransferDto } from '../../../services/kt/models';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { formatProcessingLevelFromOptions } from '../../../utils/voucherProcessingLevelOptions';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
  voucherListRowMenuHintDismissStorageKey,
} from '../../../utils/voucherListRowMenuHint';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../../utils/voucherListRowActions';
import {
  canBatchApproveVoucherRow,
  voucherBatchApproveSkippedMessage,
} from '../../../utils/voucherBatchApprove';
import { resolveVoucherBatchIds } from '../../../utils/resolveVoucherBatchIds';
import { BANK_TRANSFER_CONFIG } from '../../../features/kt/bank-transfer/shared/config/bankTransferConfig';
import { bankTransferLabels } from '../../../constants/bankTransferLabels';
import { BANK_TRANSFER_LIST_INIT_FORM } from '../../../constants/bankTransferInit';
import { TRANSFER_REASON_FILTER_OPTIONS } from '../../../constants/transferReasonLabels';
import { LIST_FILTER_SCOPE } from '../../../constants/listFilterScopes';
import erp from '../../../styles/erpPage.module.css';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../../../components/list/VoucherListPagination';
import { useVoucherListTableBusy } from '../../../components/list/useVoucherListTableBusy';
import { ProcessingLevelApproveModal } from '../../../components/voucher/ProcessingLevelApproveModal';
import { VoucherPrintModal, VoucherPostedLedgerModal } from '../../../components/voucher';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../../../components/voucher-list';
import {
  CatalogListGridFromSchema,
  ListUiSchemaEditorModal,
  listVisibleFields,
  useCatalogUiSchema,
} from '../../../components/listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../../types/catalogUiSchema';

const PAGE_SIZE = DEFAULT_PAGE_SIZE;
const testIdPrefix = BANK_TRANSFER_CONFIG.testIdPrefix;
const pageId = testIdPrefix;
const listPath = BANK_TRANSFER_CONFIG.listPath;

const ChuyenTienNoiBoListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useInAppNavigate();
  const viewMobile = useViewMobileLayout();

  const { processingLevelOptions, defaultProcessingLevel } = useVoucherInitData(BANK_TRANSFER_LIST_INIT_FORM);
  const {
    canCreate,
    canApprove,
    canUnpost,
    canUpdate,
    canPrint,
    canViewLedger: canViewLedgerPerm,
  } = useVoucherListActions(BANK_TRANSFER_LIST_INIT_FORM);

  const processingFilterOptions = useMemo(
    () => [{ value: '', label: bankTransferLabels.filterAllLevels }, ...processingLevelOptions],
    [processingLevelOptions],
  );

  const reasonFilterOptions = useMemo(
    () => [{ value: '', label: bankTransferLabels.filterAllReasons }, ...TRANSFER_REASON_FILTER_OPTIONS],
    [],
  );

  const formatProcessingLabel = (level: string | undefined) =>
    formatProcessingLevelFromOptions(level, processingLevelOptions);

  const {
    initialized,
    fromDate,
    toDate,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(LIST_FILTER_SCOPE.ktCtnb);

  const [transferReasonCode, setTransferReasonCode] = useState('');
  const [items, setItems] = useState<BankInternalTransferDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(PAGE_SIZE);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: BankInternalTransferDto } | null>(null);

  const uiSchemaKind = LIST_UI_SCHEMA_KIND.bankInternalTransfer;
  const sampleRow = useMemo(
    () => (items[0] ? (items[0] as unknown as Record<string, unknown>) : null),
    [items],
  );
  const { schema, reload: reloadSchema } = useCatalogUiSchema(uiSchemaKind, { sampleRow });
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const selection = useVoucherListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
  });

  const activeRow = selection.activeRow;
  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow ? canEditFromListRow(activeRow, canUpdate) : false;
  const canViewLedgerActive = activeRow
    ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm)
    : false;
  const canPrintActive = Boolean(activeRow) && canPrint;

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    resetPage();
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      ktService
        .getBankTransfers({
          fromDate,
          toDate,
          transferReasonCode: transferReasonCode || undefined,
          processingLevel: processingLevel || undefined,
          search: search || undefined,
          page,
          pageSize,
        })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, {
              message: getApiErrorMessage(err, bankTransferLabels.listLoadError),
              type: 'error',
            });
          }
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  }, [
    initialized,
    fromDate,
    toDate,
    transferReasonCode,
    processingLevel,
    search,
    page,
    pageSize,
    reloadKey,
    dispatch,
  ]);

  const handleBatchApproveConfirm = async (nextLevel: string) => {
    setApproving(true);
    try {
      const totalSelected = selection.selectionMode === 'all' ? totalCount : selection.selectedCount;
      const ids = await resolveVoucherBatchIds(
        selection,
        items,
        (p, ps) => ktService.getBankTransfers({
          fromDate,
          toDate,
          search: search || undefined,
          processingLevel: processingLevel || undefined,
          transferReasonCode: transferReasonCode || undefined,
          page: p,
          pageSize: ps,
        }),
        totalCount,
        row => canBatchApproveVoucherRow(row, nextLevel, { canUnpost }),
      );
      if (ids.length === 0) {
        dispatchAppToast(dispatch, {
          message: voucherBatchApproveSkippedMessage(totalSelected, totalSelected),
          type: 'warning',
        });
        return;
      }
      await BANK_TRANSFER_CONFIG.batchUpdateProcessingLevel({
        ids,
        processingLevel: nextLevel,
      });
      const skippedMsg = voucherBatchApproveSkippedMessage(totalSelected - ids.length, totalSelected);
      if (skippedMsg) {
        dispatchAppToast(dispatch, { message: skippedMsg, type: 'warning' });
      }
      dispatchAppToast(dispatch, { message: bankTransferLabels.approveSuccess, type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (error: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(error, bankTransferLabels.approveError),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const navigateToRow = useCallback(
    (id: string, startInEditMode?: boolean) => {
      navigate(`${listPath}/${id}`, {
        state: startInEditMode ? { startInEditMode: true } : undefined,
      });
    },
    [navigate],
  );

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: BankInternalTransferDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (canEditFromListRow(row, canUpdate)) {
            navigateToRow(row.id, true);
          }
          break;
        case 'viewLedger':
          if (canViewLedgerFromListRow(row, canViewLedgerPerm)) {
            setShowLedgerModal(true);
          }
          break;
        case 'print':
          if (canPrint) {
            setShowPrintModal(true);
          }
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, canUpdate, canViewLedgerPerm, canPrint, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow ? canEditFromListRow(rowMenuRow, canUpdate) : false;
  const rowMenuViewLedgerDisabled = rowMenuRow
    ? !canViewLedgerFromListRow(rowMenuRow, canViewLedgerPerm)
    : true;
  const rowMenuPrintDisabled = !canPrint;

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix,
      onRefresh: refresh,
      canApprove,
      approveDisabled: selection.selectedCount === 0,
      onApprove: () => setShowApproveModal(true),
      canViewLedger: canViewLedgerActive,
      onViewLedger: () => setShowLedgerModal(true),
      canPrint: canPrintActive,
      onPrint: () => setShowPrintModal(true),
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate,
      onCreate: () => navigate(`${listPath}/them`),
      onEditConfig: () => setShowSchemaEditor(true),
    }),
    [
      canApprove,
      selection.selectedCount,
      canViewLedgerActive,
      canPrintActive,
      canViewActive,
      canEditActive,
      canCreate,
      activeRow,
      refresh,
      navigate,
      navigateToRow,
    ],
  );

  const handleFilterSearch = useCallback(() => {
    pulseSearch(() => {
      resetPage();
      setSearch(searchDraft.trim());
      setReloadKey(k => k + 1);
    });
  }, [pulseSearch, resetPage, searchDraft, setSearch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={testIdPrefix}
        fromDate={fromDate}
        toDate={toDate}
        onDateChange={(from, to) => {
          applyDateRange(from, to, detectDateRangePreset(from, to) || 'custom');
          resetPage();
        }}
        onSearch={handleFilterSearch}
        loading={showTableLoading}
        leading={(
          <>
            <div data-testid={`${testIdPrefix}-field-search`}>
              <SearchTextInput
                label="Tìm"
                value={searchDraft}
                onChange={setSearchDraft}
                onSearch={handleFilterSearch}
                data-testid={`${testIdPrefix}-filter-search`}
              />
            </div>
            <div data-testid={`${testIdPrefix}-field-transferReasonCode`}>
              <Select
                label={bankTransferLabels.transferReasonCode}
                value={transferReasonCode}
                onChange={e => {
                  setTransferReasonCode(e.target.value);
                  resetPage();
                }}
                options={reasonFilterOptions as unknown as Array<{ value: string; label: string }>}
                data-testid={`${testIdPrefix}-filter-transferReasonCode`}
              />
            </div>
            <div data-testid={`${testIdPrefix}-field-processingLevel`}>
              <Select
                label={bankTransferLabels.processingLevel}
                value={processingLevel}
                onChange={e => {
                  setProcessingLevel(e.target.value);
                  resetPage();
                }}
                options={processingFilterOptions}
                data-testid={`${testIdPrefix}-filter-processingLevel`}
              />
            </div>
          </>
        )}
      />
    ),
    [
      testIdPrefix,
      fromDate,
      toDate,
      searchDraft,
      transferReasonCode,
      processingLevel,
      reasonFilterOptions,
      processingFilterOptions,
      applyDateRange,
      resetPage,
      setProcessingLevel,
      setSearchDraft,
      handleFilterSearch,
      showTableLoading,
    ],
  );

  const batchBar = selection.selectedCount > 0 ? (
    <div className={erp.batchBar} data-testid={`${testIdPrefix}-batch-bar`}>
      <span>{bankTransferLabels.selectedPrefix} {selection.selectedCount}</span>
      <button
        type="button"
        className={erp.batchBarLink}
        data-testid={`${testIdPrefix}-batch-clear`}
        onClick={selection.clearSelection}
      >
        {bankTransferLabels.clearAll}
      </button>
    </div>
  ) : null;

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty}>{bankTransferLabels.empty}</div>
  ) : !showTableLoading && listColumns.length > 0 ? (
    <CatalogListGridFromSchema
      testIdPrefix={testIdPrefix}
      rows={items}
      page={page}
      pageSize={pageSize}
      columns={listColumns}
      schema={schema}
      selection={selection}
      getRowId={r => r.id}
      formatProcessingLevel={formatProcessingLabel}
      gridProps={{
        onRowOpenActionMenu: handleRowOpenActionMenu,
        rowMenuHintMessage,
        rowMenuHintDismissStorageKey: voucherListRowMenuHintDismissStorageKey(testIdPrefix),
        enableRowMenuLongPress: viewMobile,
      }}
    />
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={testIdPrefix}
        pageId={pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: bankTransferLabels.listPageTitle,
          titleIconClass: 'fas fa-right-left',
          pageId,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={batchBar}
        listTitle={`Danh sách ${bankTransferLabels.listPageTitle.toLowerCase()}`}
        listRowMenuHelp
        filters={listFilters}
        listLayoutVariant="erp-filter-bar"
        listHeaderClassName={LIN_ERP_LIST_FILTER_LAYOUT.header}
        listFiltersClassName={LIN_ERP_LIST_FILTER_LAYOUT.filtersHost}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={(
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => {
              setPage(p);
              selection.clearSelection();
            }}
            onPageSizeChange={setPageSize}
          />
        )}
        modals={(
          <>
            <ProcessingLevelApproveModal
              isOpen={showApproveModal}
              onClose={() => setShowApproveModal(false)}
              currentLevel={defaultProcessingLevel ?? ''}
              levelOptions={processingLevelOptions}
              onConfirm={handleBatchApproveConfirm}
              saving={approving}
              testIdPrefix={testIdPrefix}
              batchMode
              selectedCount={selection.selectedCount}
            />
            {activeRow && (
              <>
                <VoucherPrintModal
                  isOpen={showPrintModal}
                  onClose={() => setShowPrintModal(false)}
                  voucherTitle={`${bankTransferLabels.title} — ${activeRow.code}`}
                  onPrint={handlePrintConfirm}
                  printing={printing}
                  testIdPrefix={testIdPrefix}
                />
                <VoucherPostedLedgerModal
                  isOpen={showLedgerModal}
                  onClose={() => setShowLedgerModal(false)}
                  voucherTitle={`${bankTransferLabels.title} — ${activeRow.code}`}
                  testIdPrefix={testIdPrefix}
                  fetchPostedLedger={() => BANK_TRANSFER_CONFIG.getPostedLedger(activeRow.id)}
                  fetchPostingStatus={() => BANK_TRANSFER_CONFIG.getPostingStatus(activeRow.id)}
                />
              </>
            )}
            <ListUiSchemaEditorModal
              testIdPrefix={testIdPrefix}
              catalogKind={uiSchemaKind}
              sampleRow={sampleRow}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => {
                reloadSchema();
                refresh();
              }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={testIdPrefix}
              showView
              showEdit={rowMenuShowEdit}
              showViewLedger
              showPrint
              viewLedgerDisabled={rowMenuViewLedgerDisabled}
              printDisabled={rowMenuPrintDisabled}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default ChuyenTienNoiBoListPage;
